-- Targeted migration: fill TDS-C01 + ANALYTICS-101 exam families with grounded questions.
-- Specialist (TDS-C01): 5 newly-created P-variants get 45 questions each (P5 already has 60
-- from the renamed orphan).
-- Foundations (Analytics-101): all 6 P-variants get 40 questions each.
-- Total: 225 + 240 = 465 INSERTs.
-- Idempotent via WHERE NOT EXISTS on (examId, stem).
-- Does NOT touch published, deletedAt, or any Exam field.

CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- TDS-C01-P1: 45 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop user wants to connect to a snapshot of their database that loads faster than querying the live source. Which connection type should they choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Live connection"},{"id":"b","text":"Extract (.hyper file)"},{"id":"c","text":"Data blend"},{"id":"d","text":"Cross-database join"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$According to the source material, an Extract (.hyper file) is an 'in-memory snapshot' that is 'faster' than querying the source directly. A Live connection queries the source in real time and does not provide the speed advantage of an extract. Data blending and cross-database joins are methods for combining multiple data sources, not for improving query performance via snapshots.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau — Extract Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
