         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_number.htm","label":"Tableau Number Functions – FLOOR"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
