INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau author has two measures they want to plot against the same date axis in a single chart, each using its own independent scale. Which technique should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Dual axis with synchronized axes"},{"id":"b","text":"Dual axis with independent (non-synchronized) axes"},{"id":"c","text":"Blended axis"},{"id":"d","text":"Separate sheets placed side by side on a dashboard"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states 'Dual axis (two measures on same x-axis)' and notes that 'Synchronize axis' is used for comparable scales. When each measure needs its OWN independent scale, a dual axis WITHOUT synchronization is appropriate. Synchronizing the axes would force them to share the same scale, defeating the purpose. A blended axis merges the measures onto one shared axis, and separate sheets do not constitute a dual axis.$patch$, $patch$Sharing Insights$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/multiple_measures.htm","label":"Tableau — Dual Axis Charts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
