INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to share a workbook that includes its underlying data so that a colleague without Tableau Desktop can view it offline using Tableau Reader. Which file format should the analyst save the workbook as?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":".twb"},{"id":"b","text":".tds"},{"id":"c","text":".twbx"},{"id":"d","text":".hyper"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A .twbx (packaged workbook) bundles the workbook XML together with a copy of the data extract, making it self-contained and viewable in Tableau Reader without a live connection. A .twb is an XML file that references external data but does not embed it, so the recipient would need access to the original data source. A .tds is a saved data-source connection definition only (no workbook content). A .hyper file is the raw extract data format and is not a viewable workbook. Source passage: 'twbx (packaged workbook with data extract)' and 'Tableau Reader (free viewer).'$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/environ_filesandfolders.htm","label":"Tableau File Types and Folders – Tableau Desktop and Web Authoring Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to share a workbook that includes its underlying data so that a colleague without Tableau Desktop can view it offline using Tableau Reader. Which file format should the analyst save the workbook as?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's order of operations, which filter type is evaluated BEFORE dimension filters but AFTER extract filters and data source filters?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Measure filters"},{"id":"b","text":"Context filters"},{"id":"c","text":"INCLUDE LOD filters"},{"id":"d","text":"Table calculation filters"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$According to Tableau's order of operations, the sequence is: Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calcs. Context filters are therefore evaluated third — after extract and data source filters but before FIXED LODs and dimension filters. INCLUDE/EXCLUDE LODs come after dimension filters, measure filters come after those, and table calculation filters are last. Source passage: 'Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calcs.'$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Tableau Order of Operations – Tableau Desktop and Web Authoring Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau's order of operations, which filter type is evaluated BEFORE dimension filters but AFTER extract filters and data source filters?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When a date field is set to Continuous in Tableau, what is the primary visual effect on the view compared to setting the same field to Discrete?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The date field is moved from the Columns shelf to the Rows shelf automatically."},{"id":"b","text":"The date field creates an axis rather than individual column or row headers."},{"id":"c","text":"The date field is aggregated as a measure instead of a dimension."},{"id":"d","text":"The date field is displayed as a blue pill instead of a green pill."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Continuous fields create axes; discrete fields create headers.' When a date is Continuous (green), Tableau renders a continuous numeric axis, allowing values between data points to be represented. When Discrete (blue), Tableau renders individual column or row headers for each distinct date part. Option A is incorrect — shelf placement is unrelated to continuous/discrete setting. Option C is incorrect — continuous vs. discrete is independent of the dimension/measure classification. Option D reverses the color coding: Continuous fields are green and Discrete fields are blue, not the other way around.$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/datafields_typesandroles_datesdates.htm","label":"Discrete vs. Continuous Date Fields – Tableau Desktop Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When a date field is set to Continuous in Tableau, what is the primary visual effect on the view compared to setting the same field to Discrete?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization's analysts currently use Tableau Desktop and want to enable colleagues to access and interact with published dashboards through a web browser without managing any server infrastructure themselves. Which Tableau product best meets this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tableau Reader"},{"id":"b","text":"Tableau Bridge"},{"id":"c","text":"Tableau Cloud"},{"id":"d","text":"Tableau Prep Builder"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau Cloud (formerly Tableau Online) is the SaaS offering that hosts published dashboards on Anthropic-managed (Salesforce-managed) infrastructure, so the organization does not need to maintain any servers. Tableau Reader is a free standalone desktop viewer for packaged workbooks and does not support browser-based web access. Tableau Bridge is a connectivity tool that keeps Tableau Cloud connected to on-premises data sources — it does not itself host dashboards. Tableau Prep Builder is a data preparation tool, not a publishing or viewing platform. Source passage: 'Tableau Cloud (SaaS, formerly Tableau Online).'$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/online/en-us/to_get_started.htm","label":"Tableau Cloud Overview – Tableau Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization's analysts currently use Tableau Desktop and want to enable colleagues to access and interact with published dashboards through a web browser without managing any server infrastructure themselves. Which Tableau product best meets this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau, which of the following best describes the role of a Dimension field?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A numeric field that Tableau automatically aggregates using SUM or AVG."},{"id":"b","text":"A qualitative, categorical field used to group and segment data in the view."},{"id":"c","text":"A green pill that always produces a continuous axis when placed on a shelf."},{"id":"d","text":"A field stored exclusively in the .hyper extract file format."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material defines Dimensions as 'qualitative (categorical) — used for grouping/segmenting' data. Measures, not Dimensions, are the quantitative fields that Tableau automatically aggregates (option A). While Dimensions are typically displayed as blue (discrete) pills, Continuous fields (green) create axes — but a Dimension is not defined by its color or axis behavior (option C). File format (.hyper) is unrelated to the dimension/measure classification (option D).$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/datafields_typesandroles.htm","label":"Dimensions and Measures, Blue and Green – Tableau Desktop Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
