INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop user needs to query data in real time directly from a SQL Server database without storing a local copy. Which connection type should they choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract"},{"id":"b","text":"Live"},{"id":"c","text":"Published Data Source"},{"id":"d","text":"Data Blend"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection queries the data source in real time, meaning every interaction sends a query directly to the database. As stated in the source material: 'Live (real-time query against source).' An Extract creates a local .hyper snapshot (faster but not real-time). A Published Data Source is a sharing mechanism, not a connection type. Data Blend combines multiple connections but does not define query behavior.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau Help – Live Connections and Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
