  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Desktop user needs to query data in real time directly from a SQL Server database without storing a local copy. Which connection type should they choose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When Tableau Desktop saves an Extract, what file format is used to store the in-memory snapshot?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":".twbx"},{"id":"b","text":".tde"},{"id":"c","text":".hyper"},{"id":"d","text":".xlsx"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material explicitly states that an Extract is a '.hyper file, in-memory snapshot, faster.' The older .tde format was retired in Tableau 10.5 and replaced by .hyper. A .twbx is a packaged workbook, and .xlsx is a Microsoft Excel file format — neither is the extract format.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extract_upgrade.htm","label":"Tableau Help – Extract Upgrade to .hyper Format"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
