INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data analyst connects to an Excel workbook that contains merged cells, extra header rows, and footer rows. Which Tableau Desktop feature should they use to automatically clean this formatting?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Pivot"},{"id":"b","text":"Split"},{"id":"c","text":"Data Interpreter"},{"id":"d","text":"Union"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Data Interpreter: auto-clean Excel data (remove headers/footers/merged cells).' Pivot converts wide data to long format. Split parses text by a delimiter. Union stacks rows from multiple tables. None of these address merged cells or extra header/footer rows the way Data Interpreter does.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/data_interpreter.htm","label":"Tableau Help – Clean Data from Excel with Data Interpreter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
