         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau Help — Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
