INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When building a dashboard in Tableau, which layout principle is recommended to ensure the most important information receives the most user attention?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Place the most important content in the bottom-right corner to anchor the viewer's eye."},{"id":"b","text":"Use as many colors as possible to draw attention across the entire dashboard."},{"id":"c","text":"Place the most important information in the top-left area, following the F or Z reading pattern."},{"id":"d","text":"Maximize the number of charts on the dashboard to provide comprehensive context."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Dashboard layout: F or Z reading pattern; most important info top-left.' Viewers naturally scan content starting from the top-left, so placing key insights there maximizes visibility. The source also emphasizes 'less is more' and using 'color sparingly,' making options b and d contradict best practices. Option a contradicts the F/Z reading pattern guidance.$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_best_practices.htm","label":"Dashboard Design Best Practices — Tableau Documentation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
