INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop user wants data to always reflect the most current state of the underlying database without any scheduled refresh. Which connection type should they choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract (.hyper file)"},{"id":"b","text":"Live connection"},{"id":"c","text":"Published data source"},{"id":"d","text":"Data blend"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection queries the underlying data source in real time, so every view reflects the most current data without any extract refresh. The source material states: 'Live (real-time query against source) vs Extract (.hyper file, in-memory snapshot, faster).' An Extract (.hyper) is a snapshot that requires a refresh to show updated data. A published data source and data blend are delivery/combination mechanisms, not connection modes that guarantee real-time freshness on their own.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau – Live Connections and Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
