INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau user has an Excel workbook whose data starts on row 5 because rows 1–4 contain a company logo and merged header cells. Which Data Source page feature should the user apply to automatically clean this structure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Pivot"},{"id":"b","text":"Data Interpreter"},{"id":"c","text":"Split"},{"id":"d","text":"Union"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Data Interpreter: auto-clean Excel data (remove headers/footers/merged cells).' Data Interpreter detects and removes extraneous formatting artifacts like logos, merged cells, and extra header rows. Pivot transforms wide data to long format. Split parses delimited text columns. Union stacks tables with matching columns.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/data_interpreter.htm","label":"Tableau – Clean Data from Excel with Data Interpreter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
