INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Quick Table Calculation would you apply to a bar chart showing monthly sales to display each month's sales as a proportion of the total annual sales?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Running Total"},{"id":"b","text":"Difference"},{"id":"c","text":"Percent of Total"},{"id":"d","text":"Moving Average"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The 'Percent of Total' Quick Table Calculation divides each value by the sum of all values in the partition, expressing each mark as a percentage of the whole. This is exactly what is needed to show each month's share of annual sales. 'Running Total' accumulates values progressively. 'Difference' computes the change between consecutive marks. 'Moving Average' smooths values over a rolling window — none of these produce a proportion-of-total result.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_quick.htm","label":"Tableau Help — Quick Table Calculations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
