INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In a Tableau calculated field, which function returns the number of characters in a string?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"FIND"},{"id":"b","text":"MID"},{"id":"c","text":"LEN"},{"id":"d","text":"SPLIT"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$LEN(string) returns the number of characters in the given string. For example, LEN('Tableau') returns 7. FIND returns the position of a substring within a string. MID returns a substring starting at a specified position. SPLIT divides a string by a delimiter and returns a token. None of those other functions return the character count.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_string.htm","label":"Tableau Help — String Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
