INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A user drags a measure onto the 'Detail' shelf of the Marks card. What is the primary effect of this action?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The measure is aggregated and displayed as a label on each mark"},{"id":"b","text":"The measure adds granularity to the view without visually encoding the data with size or color"},{"id":"c","text":"The measure is used to color-code each mark in the view"},{"id":"d","text":"The measure creates a reference line at its average value"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Placing a field on the Detail shelf increases the level of detail in the view — it adds granularity — without changing the visual encoding (color, size, shape, label, or tooltip). This is useful when you want to break data down to a finer grain for tooltip display or mark-level calculations without altering the chart's appearance. Placing a field on Label shows values on marks. Color encodes data visually with a color scale. Reference lines come from the Analytics pane, not the Marks card.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/marks_marktypes.htm","label":"Tableau Help — Change the Type of Mark in the View"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/buildmanual_shelves_marks.htm","label":"Tableau Help — Marks Card Reference"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
