INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which LOD expression syntax computes an aggregation that is FIXED at a specified dimension level, regardless of what dimensions are in the view?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"{ INCLUDE [Dimension] : AGG(Measure) }"},{"id":"b","text":"{ EXCLUDE [Dimension] : AGG(Measure) }"},{"id":"c","text":"{ FIXED [Dimension] : AGG(Measure) }"},{"id":"d","text":"{ WINDOW_SUM(AGG(Measure)) }"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$FIXED LOD expressions compute a result at the level of the specified dimension(s) regardless of what dimensions exist in the current view. For example, { FIXED [Customer ID] : SUM([Sales]) } always computes total sales per customer even if Customer ID is not on the view. INCLUDE adds a dimension to the view-level calculation. EXCLUDE removes a dimension from the view-level calculation. WINDOW_SUM is a table calculation function, not an LOD expression.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau Help — Level of Detail Expressions"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod_fixed.htm","label":"Tableau Help — FIXED LOD"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which LOD expression syntax computes an aggregation that is FIXED at a specified dimension level, regardless of what dimensions are in the view?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field uses the expression: DATEDIFF('month', [Order Date], [Ship Date]). What does this expression return?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The date that is a specified number of months after the Order Date"},{"id":"b","text":"The number of complete months between Order Date and Ship Date"},{"id":"c","text":"The month portion of the Order Date as an integer"},{"id":"d","text":"A truncated date value rounded to the nearest month"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$DATEDIFF(date_part, start_date, end_date) returns the difference between two dates in the units specified by date_part. With 'month' as the date_part, it returns the number of complete months between Order Date and Ship Date. DATEADD adds an interval to a date. DATEPART extracts a specific part (like month number) from a date. DATETRUNC truncates a date to the start of a specified period. Each serves a different purpose.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm","label":"Tableau Help — Date Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field uses the expression: DATEDIFF('month', [Order Date], [Ship Date]). What does this expression return?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau feature allows a dashboard user to change a value (such as a threshold or a time period) at runtime that then updates calculations referencing that value?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Group"},{"id":"b","text":"Set"},{"id":"c","text":"Parameter"},{"id":"d","text":"Context filter"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Parameters are user-editable single values that can be referenced in calculated fields, filters, reference lines, and other Tableau features. When a user adjusts a parameter control on a dashboard, any calculation or filter that references that parameter updates dynamically. Groups statically combine dimension members. Sets define in/out membership. Context filters restrict the dataset foundation but are not user-editable values.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/parameters_create.htm","label":"Tableau Help — Create Parameters"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau feature allows a dashboard user to change a value (such as a threshold or a time period) at runtime that then updates calculations referencing that value?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's Analytics pane, which model type uses exponential smoothing to project future values based on historical trends and seasonality?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Trend Line"},{"id":"b","text":"Cluster"},{"id":"c","text":"Reference Band"},{"id":"d","text":"Forecast"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Tableau's Forecasting feature, found in the Analytics pane, uses exponential smoothing models to project future values. It accounts for trend and seasonality in the historical data. Trend Lines fit a mathematical model (linear, logarithmic, exponential, or polynomial) to existing data but do not project forward as a forecast. Cluster uses k-means to group marks. Reference Bands show a shaded region between two values — neither clusters nor reference bands project time-series forecasts.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_create.htm","label":"Tableau Help — Create a Forecast"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_how_it_works.htm","label":"Tableau Help — How Forecasting Works"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau's Analytics pane, which model type uses exponential smoothing to project future values based on historical trends and seasonality?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which logical function should you use to replace a NULL value in a field with zero (0)?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"ISNULL"},{"id":"b","text":"IFNULL"},{"id":"c","text":"ZN"},{"id":"d","text":"NOT"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$ZN(expression) is the most concise way to replace NULLs with zero: it returns the expression value if it is not null, otherwise returns 0. IFNULL(expression, replacement) can also replace NULLs but requires specifying a replacement value explicitly — e.g., IFNULL([Sales], 0). ISNULL only tests whether a value is null (returns TRUE/FALSE) and does not replace it. NOT is a Boolean negation operator. While IFNULL could technically work, ZN is the purpose-built shorthand for replacing NULLs with zero.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_logical.htm","label":"Tableau Help — Logical Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which logical function should you use to replace a NULL value in a field with zero (0)?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A user wants to show only the Top 5 products by Sales in a view. Which Tableau filter type is purpose-built for this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Dimension filter using a list of specific values"},{"id":"b","text":"Measure filter with a range condition"},{"id":"c","text":"Top N filter"},{"id":"d","text":"Context filter"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The Top N filter is specifically designed to limit a view to the top (or bottom) N members of a dimension ranked by a measure. Selecting 'Top 5 by Sales' on a Product dimension filter is the direct use case. A dimension filter using a list requires manually selecting members. A measure filter restricts based on a numeric range but does not rank and limit by count. A context filter establishes a foundational subset but does not itself perform Top N ranking.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filtering_top.htm","label":"Tableau Help — Filter Top and Bottom Values"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A user wants to show only the Top 5 products by Sales in a view. Which Tableau filter type is purpose-built for this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$What does the ATTR() aggregation function return when all values in a group are identical?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The sum of all values in the group"},{"id":"b","text":"An asterisk (*) indicating multiple values"},{"id":"c","text":"The single shared value when all values are the same; an asterisk (*) if they differ"},{"id":"d","text":"Always NULL regardless of the data"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$ATTR(expression) checks whether all values within a group have the same single value. If they do, ATTR returns that value; if there are multiple distinct values, it returns an asterisk (*) to signal ambiguity. This makes ATTR useful when you want to treat a dimension as if it were a measure aggregation — confirming uniqueness. SUM is a different aggregation. ATTR never unconditionally returns NULL.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_aggregate.htm","label":"Tableau Help — Aggregate Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$What does the ATTR() aggregation function return when all values in a group are identical?$patch$);
