  SELECT gen_random_uuid()::text, e.id, $patch$Which Quick Table Calculation computes the cumulative sum of a measure across marks in the view?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Percent of Total"},{"id":"b","text":"Running Total"},{"id":"c","text":"Moving Average"},{"id":"d","text":"Rank"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Running Total accumulates (sums) values progressively from the first mark to the current mark, producing a cumulative total. Percent of Total divides each value by the grand total. Moving Average calculates the average over a rolling window of consecutive marks. Rank assigns an ordinal position to each mark based on its value. None of the other options produce a cumulative sum.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_quick.htm","label":"Tableau Help — Quick Table Calculations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Quick Table Calculation computes the cumulative sum of a measure across marks in the view?$patch$);
