  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field contains: IF [Profit] > 0 THEN 'Profitable' ELSE 'Unprofitable' END. Which syntax construct is being used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"CASE/WHEN"},{"id":"b","text":"IIF"},{"id":"c","text":"IF/THEN/ELSE"},{"id":"d","text":"ISNULL"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The expression uses the IF/THEN/ELSE/END syntax, which evaluates a Boolean condition and returns different values depending on whether the condition is true or false. CASE/WHEN matches a single expression against a list of specific values (not Boolean conditions). IIF is a single-line inline if function. ISNULL is a function that tests for NULL values. The structure 'IF [condition] THEN [value] ELSE [value] END' is the canonical IF/THEN/ELSE form.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_logical.htm","label":"Tableau Help — Logical Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field contains: IF [Profit] > 0 THEN 'Profitable' ELSE 'Unprofitable' END. Which syntax construct is being used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which option in the 'Compute Using' setting for a table calculation means the calculation is applied independently within each pane of a crosstab?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Table (Across)"},{"id":"b","text":"Table (Down)"},{"id":"c","text":"Pane"},{"id":"d","text":"Cell"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The 'Pane' option scopes a table calculation so that it resets and computes independently within each pane (sub-section) of the crosstab created by partitioning dimensions. 'Table (Across)' computes across all columns in the entire table. 'Table (Down)' computes down all rows in the entire table. 'Cell' computes within a single cell. When you need a calculation like Percent of Total to sum to 100% within each sub-group rather than the entire table, 'Pane' is the correct scope.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_definebasics.htm","label":"Tableau Help — Table Calculation Scope and Direction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
