  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which option in the 'Compute Using' setting for a table calculation means the calculation is applied independently within each pane of a crosstab?$patch$);
