INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A set in Tableau defined with a 'Top N by Sales' condition is best described as which type of set?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A static set based on manually selected members"},{"id":"b","text":"A dynamic set whose membership updates as the data changes"},{"id":"c","text":"A combined set that merges two existing sets"},{"id":"d","text":"A context filter disguised as a set"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Sets defined with a condition (such as Top N by Sales) are dynamic — their membership automatically recalculates as the underlying data changes, always reflecting the current Top N members. In contrast, a static set is created by manually selecting specific members, which does not update when data changes. A combined set merges two existing sets using IN/OUT logic. Sets are not context filters, though they can be used alongside filters.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/sortgroup_sets_create.htm","label":"Tableau Help — Create Sets"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
