  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization needs employees to view Tableau workbooks without purchasing full Desktop licenses. The organization's data is sensitive and must NOT be shared publicly. Which Tableau product is the most appropriate free option for these read-only viewers?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When designing a Tableau dashboard, where should the most critical information ideally be positioned to align with established visual best practices for reading patterns?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Bottom-right corner, so it is the last thing the viewer sees"},{"id":"b","text":"Center of the dashboard for equal visual weight"},{"id":"c","text":"Top-left area, following the F or Z reading pattern"},{"id":"d","text":"Bottom-left corner, anchoring the viewer's attention"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau visual best practices recommend placing the most important information in the top-left area of a dashboard. This aligns with how most viewers naturally scan content — following an F-shaped or Z-shaped reading pattern that begins at the top-left. Placing critical content in the bottom-right or center does not leverage these natural reading tendencies. Source: 'Dashboard layout: F or Z reading pattern; most important info top-left.'$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_best_practices.htm","label":"Tableau — Best Practices for Dashboard Design"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
