  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When designing a Tableau dashboard, where should the most critical information ideally be positioned to align with established visual best practices for reading patterns?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's order of operations, which filter type is evaluated BEFORE dimension filters but AFTER extract filters and data source filters?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Measure filters"},{"id":"b","text":"Table calculation filters"},{"id":"c","text":"Context filters"},{"id":"d","text":"INCLUDE LOD filters"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau's order of operations (pipeline) is: Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calculation filters. Context filters are therefore evaluated third in the pipeline — after extract and data source filters, but before dimension filters. Measure filters and table calculation filters are evaluated much later in the pipeline. INCLUDE LOD filters are evaluated after dimension filters. Source: 'Tableau order of operations: Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calcs.'$patch$, $patch$Understanding Tableau Concepts$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Tableau — Order of Operations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau's order of operations, which filter type is evaluated BEFORE dimension filters but AFTER extract filters and data source filters?$patch$);

