INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop user wants to connect to a data source that is refreshed in real-time, querying the underlying database every time the workbook is opened or a filter is applied. Which connection type should they choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract (.hyper)"},{"id":"b","text":"Live"},{"id":"c","text":"Published Data Source"},{"id":"d","text":"Data Blend"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection queries the underlying data source in real-time every time the workbook is loaded or a filter is changed, ensuring up-to-date results. An Extract (.hyper file) is an in-memory snapshot taken at a point in time and is faster but not real-time. A Published Data Source is a way to share a connection, not a connection type itself. Data Blending combines multiple connections but does not describe real-time behavior. The source material states: 'Live (real-time query against source) vs Extract (.hyper file, in-memory snapshot, faster).'$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau Help — Live Connections vs Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Desktop user wants to connect to a data source that is refreshed in real-time, querying the underlying database every time the workbook is opened or a filter is applied. Which connection type should they choose?$patch$);
