         $json$[{"id":"a","text":"Union"},{"id":"b","text":"Split"},{"id":"c","text":"Pivot"},{"id":"d","text":"Data Interpreter"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Pivot transforms wide data into long format by converting multiple columns (Q1, Q2, Q3, Q4) into rows — producing a single 'Pivot Field Names' column (Quarter) and a single 'Pivot Field Values' column (Sales). This is exactly the wide-to-long transformation described in the source material: 'Pivot: transform wide data to long (multiple columns to one column).' Union stacks rows from separate tables vertically. Split breaks one column into multiple columns by a delimiter. Data Interpreter cleans Excel formatting artifacts.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/pivot.htm","label":"Tableau Help — Pivot Data from Columns to Rows"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
