         $json$[{"id":"a","text":"Each cell's value as a percentage of the grand total for the entire table"},{"id":"b","text":"Each cell's value as a percentage of its own row total only"},{"id":"c","text":"Each cell's value as a percentage of the column total"},{"id":"d","text":"Each cell's value as a percentage of the pane it belongs to"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$When 'Compute Using' is set to Table (Across), Tableau partitions the entire table and computes Percent of Total so each cell is shown as a fraction of the overall grand total. 'Table (Down)' would compute down columns; 'Pane' would compute within individual pane sections. The source material lists 'Table (Across/Down)' and 'Pane' as distinct Compute Using options for Quick Table Calculations.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_definebasics_scope_direction.htm","label":"Tableau — Table Calculation Scope and Direction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
