  SELECT gen_random_uuid()::text, e.id, $patch$Which Analytics pane feature allows Tableau to automatically predict future values of a measure using exponential smoothing?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Trend Line"},{"id":"b","text":"Reference Band"},{"id":"c","text":"Forecasting"},{"id":"d","text":"Cluster"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Forecasting in Tableau uses exponential smoothing to project future values of a measure based on historical patterns. Trend Lines fit a mathematical model (linear, log, etc.) to existing data but do not predict future periods. Reference Bands highlight value ranges. Cluster uses k-means to group marks. The source material states 'Forecasting (exponential smoothing)' under the Analytics pane section.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_create.htm","label":"Tableau — Create a Forecast"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Analytics pane feature allows Tableau to automatically predict future values of a measure using exponential smoothing?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field contains: IF [Sales] > 1000 THEN 'High' ELSEIF [Sales] > 500 THEN 'Medium' ELSE 'Low' END. What type of Tableau syntax is this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"CASE/WHEN syntax"},{"id":"b","text":"IF/THEN/ELSE syntax"},{"id":"c","text":"FIXED LOD syntax"},{"id":"d","text":"IIF syntax"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The formula uses IF ... THEN ... ELSEIF ... THEN ... ELSE ... END, which is IF/THEN/ELSE syntax. CASE/WHEN syntax would look like CASE [Field] WHEN value THEN result ... END and tests equality against a single expression rather than range conditions. FIXED LOD uses curly-brace notation. IIF is a different inline conditional function with a different signature. The source material explicitly lists 'IF/THEN/ELSE' syntax under Calculated fields.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_logical.htm#IF","label":"Tableau — IF Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field contains: IF [Sales] > 1000 THEN 'High' ELSEIF [Sales] > 500 THEN 'Medium' ELSE 'Low' END. What type of Tableau syntax is this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which mark type property on the Marks card should you use to ensure additional dimension fields appear in the tooltip without adding them to Rows, Columns, or changing the view structure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Color"},{"id":"b","text":"Size"},{"id":"c","text":"Detail"},{"id":"d","text":"Shape"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Placing a dimension on the Detail shelf of the Marks card adds it to the level of detail of the view (affecting mark granularity) and makes it available in the tooltip without encoding it visually as color, size, or shape. Tooltip shelf text can reference it, or it appears automatically. Color, Size, and Shape encode the field visually rather than silently adding it as context. The source material lists 'Detail' and 'Tooltip' as Marks card properties.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/buildmanual_shelves_marks.htm","label":"Tableau — Marks Card Reference"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which mark type property on the Marks card should you use to ensure additional dimension fields appear in the tooltip without adding them to Rows, Columns, or changing the view structure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$The formula DATETRUNC('month', [Order Date]) returns which of the following?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The integer month number (1–12) of the Order Date"},{"id":"b","text":"The Order Date truncated to the first day of its month"},{"id":"c","text":"The number of months since a fixed origin date"},{"id":"d","text":"The last day of the month containing the Order Date"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$DATETRUNC(date_part, date) truncates a date to the precision specified by date_part. 'month' precision sets the day component to 1 and removes the time component, returning the first day of that month. To get the integer month number you would use DATEPART('month', date). To calculate elapsed months you would use DATEDIFF. DATETRUNC does not return the last day of the month. The source material lists DATETRUNC under date functions.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm#DATETRUNC","label":"Tableau — DATETRUNC Function"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$The formula DATETRUNC('month', [Order Date]) returns which of the following?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You have two Sets — [High Value Customers] and [Repeat Buyers]. You want to create a new Set containing only customers who belong to BOTH sets. Which feature should you use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create a Group from both Sets"},{"id":"b","text":"Create a Combined Set using the intersection option"},{"id":"c","text":"Use a FIXED LOD to join the Sets"},{"id":"d","text":"Use a Context filter on each Set separately"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Combined Sets allow two existing Sets to be merged using set operations: union (IN either), intersection (IN both), or difference (IN one but not the other). Selecting the intersection option returns only members that belong to both source Sets. Groups are static and cannot dynamically combine Sets. A FIXED LOD is not a mechanism for combining Sets. The source material lists 'Combined Sets (IN/OUT)' as a feature.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/sortgroup_sets_combine.htm","label":"Tableau — Combine Sets"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You have two Sets — [High Value Customers] and [Repeat Buyers]. You want to create a new Set containing only customers who belong to BOTH sets. Which feature should you use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau function would you use to add exactly 30 days to a date field called [Start Date]?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"DATEDIFF('day', [Start Date], 30)"},{"id":"b","text":"DATEPART('day', [Start Date]) + 30"},{"id":"c","text":"DATEADD('day', 30, [Start Date])"},{"id":"d","text":"MAKEDATE([Start Date], 30)"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$DATEADD(date_part, increment, date) returns a new date by adding the specified increment in the given date_part to the input date. DATEADD('day', 30, [Start Date]) adds 30 days. DATEDIFF computes the difference between two dates, not an addition. DATEPART extracts a numeric component and adding 30 to it does not produce a valid date. MAKEDATE constructs a date from year, month, day components. The source material lists DATEADD under date functions.$patch$, $patch$Exploring and Analyzing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm#DATEADD","label":"Tableau — DATEADD Function"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau function would you use to add exactly 30 days to a date field called [Start Date]?$patch$);
