INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau dashboard object allows an author to embed a live external webpage directly within a dashboard?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Image object"},{"id":"b","text":"Text object"},{"id":"c","text":"Web Page object"},{"id":"d","text":"Extension object"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material lists dashboard objects including Sheet, Text, Image, Web Page, Blank, Navigation, Download, Extension, and Ask Data. The 'Web Page' object specifically embeds a live external webpage inside the dashboard. An Image object displays a static image file, a Text object shows formatted text, and an Extension object integrates a third-party application — none of these display live external webpages.$patch$, $patch$Sharing Insights$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_create.htm","label":"Tableau — Dashboard Objects"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
