INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop user wants their visualizations to always reflect the most current data without any scheduled refresh. Which connection type should they choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract (.hyper file)"},{"id":"b","text":"Live connection"},{"id":"c","text":"Published data source"},{"id":"d","text":"Cross-database join"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection queries the data source in real time, so visualizations always reflect the most current data without any manual or scheduled refresh. An Extract (.hyper file) is an in-memory snapshot that requires refreshing to pick up new data. Published data sources and cross-database joins are data organization/sharing mechanisms, not connection refresh modes.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau — Live Connections vs Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Desktop user wants their visualizations to always reflect the most current data without any scheduled refresh. Which connection type should they choose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
