INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$On the Tableau Data Source page, a user drags two tables from the same database and needs to combine all rows from both tables, which have identical column structures. Which feature should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Join"},{"id":"b","text":"Blend"},{"id":"c","text":"Union"},{"id":"d","text":"Relationship"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Union stacks rows from tables that share the same column structure, effectively appending one table's rows beneath another. This is distinct from a Join (which combines columns by matching rows on a key), a Blend (which links separate connections via a linking field), and a Relationship (which links tables in the logical layer without physical merging). The source material states: 'Unions: combine tables with same columns.'$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau — Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$On the Tableau Data Source page, a user drags two tables from the same database and needs to combine all rows from both tables, which have identical column structures. Which feature should they use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A dataset exported from a legacy system contains Excel data with merged cells, extra header rows, and footer notes. Which Tableau Data Source page feature is designed to automatically clean this type of formatting?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Pivot"},{"id":"b","text":"Data Interpreter"},{"id":"c","text":"Split"},{"id":"d","text":"Data Blending"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The Data Interpreter is Tableau's built-in tool specifically designed to auto-clean Excel data by removing merged cells, extra headers, footers, and other formatting issues. As stated in the source: 'Data Interpreter: auto-clean Excel data (remove headers/footers/merged cells).' Pivot converts wide data to long format; Split parses text by delimiter; Data Blending combines data from multiple connections.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/data_interpreter.htm","label":"Tableau — Clean Data from Excel with Data Interpreter"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
