INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau user needs to combine data from a MySQL database and a Salesforce connection within a single data source. Which feature supports this scenario?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Wildcard Union"},{"id":"b","text":"Cross-database join"},{"id":"c","text":"Data Interpreter"},{"id":"d","text":"Tableau Prep Builder Aggregate step"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A cross-database join allows Tableau to combine data from different connections (e.g., MySQL and Salesforce) within a single data source. The source material states: 'Cross-database joins: combine data from different connections in a single data source.' A Wildcard Union is for combining files by name pattern; Data Interpreter cleans Excel formatting; the Aggregate step in Tableau Prep Builder is for summarizing data, not joining across databases.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm","label":"Tableau — Join Your Data Across Databases"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau user needs to combine data from a MySQL database and a Salesforce connection within a single data source. Which feature supports this scenario?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following best describes how Tableau Desktop's Relationships differ from physical Joins on the Data Source page?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Relationships always produce a Full Outer Join between the connected tables."},{"id":"b","text":"Relationships exist in the logical layer, use auto-aggregation, and preserve row context without merging tables physically."},{"id":"c","text":"Relationships require both tables to have identical column structures, similar to a Union."},{"id":"d","text":"Relationships can only be used when connecting to file-based data sources such as Excel or CSV."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Relationships are defined in the logical layer of the data model and allow Tableau to automatically determine join types at query time while preserving the grain (row context) of each table. The source states: 'Relationships (new model): logical layer connecting tables; auto-aggregation; preserves context.' This is distinct from physical Joins (Inner, Left, Right, Full Outer), which merge tables at the physical layer. Relationships do not require identical columns (that is a Union requirement) and are not limited to file-based sources.$patch$, $patch$Connecting to and Preparing Data$patch$,
         2, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/relate_tables.htm","label":"Tableau — Relate Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDS-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following best describes how Tableau Desktop's Relationships differ from physical Joins on the Data Source page?$patch$);
