INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau, which of the following best describes the difference between a Dimension and a Measure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Dimensions are always numeric; Measures are always text-based."},{"id":"b","text":"Dimensions are qualitative fields used for grouping; Measures are quantitative fields that are automatically aggregated."},{"id":"c","text":"Dimensions are continuous by default; Measures are discrete by default."},{"id":"d","text":"Dimensions are stored in extracts; Measures are stored only in live connections."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material defines: 'Dimensions: qualitative (categorical) — used for grouping/segmenting. Measures: quantitative — automatically aggregated.' Dimensions are typically categorical (e.g., Region, Category) and are not aggregated. Measures are numeric values (e.g., Sales, Profit) that Tableau aggregates by default (e.g., SUM, AVG). Options A, C, and D are all incorrect — Dimensions are not necessarily numeric, they are discrete by default (not continuous), and their storage is not tied to connection type.$patch$, $patch$Understanding Tableau Concepts$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/datafields_typesandroles.htm","label":"Dimensions and Measures, Blue and Green — Tableau Desktop and Web Authoring Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
