INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop, what is the key difference between a Live connection and an Extract?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A Live connection stores data in a .hyper file; an Extract queries the source in real time."},{"id":"b","text":"A Live connection queries the source in real time; an Extract is an in-memory snapshot stored locally."},{"id":"c","text":"A Live connection is only available for file-based sources; an Extract is only for databases."},{"id":"d","text":"There is no functional difference; the terms are interchangeable."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Live (real-time query against source) vs Extract (.hyper file, in-memory snapshot, faster).' Option A reverses the definitions. Option C incorrectly restricts which sources each connection type supports. Option D is factually wrong — they have distinct behaviors and performance characteristics.$patch$, $patch$Connecting to and Preparing Data$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/live_connected_to_data.htm","label":"Live Connections vs Extracts — Tableau Help"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
