INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau user wants to publish dashboards for free and share them publicly on the web without needing a paid license. Which Tableau product is designed for this purpose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tableau Desktop"},{"id":"b","text":"Tableau Server"},{"id":"c","text":"Tableau Bridge"},{"id":"d","text":"Tableau Public"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The source material explicitly states that Tableau Public is 'free, public dashboards,' meaning it allows users to publish and share dashboards at no cost. The trade-off is that all workbooks are saved to the public web and cannot be kept private. Tableau Desktop is a paid product supporting private workbooks and more connectors. Tableau Server is self-hosted and requires licensing. Tableau Bridge is a connectivity tool, not a publishing platform.$patch$, $patch$Understanding Tableau Concepts$patch$,
         1, $json$[{"url":"https://public.tableau.com/en-us/s/","label":"Tableau Public — Overview"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/getstarted_tableau_desktop.htm","label":"Which Tableau Product Is Right for You?"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
