INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau, a field displayed in GREEN on the Rows or Columns shelf will produce which type of visual result?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A set of discrete headers along the axis"},{"id":"b","text":"A continuous axis with a quantitative scale"},{"id":"c","text":"A calculated field dialog box"},{"id":"d","text":"A context filter applied to the view"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states: 'Continuous fields create axes; discrete fields create headers.' Green pills represent continuous fields in Tableau, so placing one on Rows or Columns produces a continuous axis with a quantitative or date scale. Blue pills (discrete) create individual headers or label buckets. The other options describe unrelated Tableau features.$patch$, $patch$Understanding Tableau Concepts$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/datafields_typesandroles_dataroles_continuous.htm","label":"Continuous and Discrete Fields — Tableau Desktop Documentation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
