INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In the Tableau order of operations, which type of filter is applied FIRST before all other filter types?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Context filters"},{"id":"b","text":"Dimension filters"},{"id":"c","text":"Extract filters"},{"id":"d","text":"Measure filters"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material lists the Tableau order of operations as: 'Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calcs.' Extract filters are applied at the time the extract is created — before data even enters the workbook — making them the very first step. Context filters come third, dimension filters fifth, and measure filters second-to-last.$patch$, $patch$Understanding Tableau Concepts$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Order of Operations — Tableau Desktop Documentation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'ANALYTICS-101-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In the Tableau order of operations, which type of filter is applied FIRST before all other filter types?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$According to Tableau visual best practices, where should the most important information be positioned on a dashboard to align with natural reading patterns?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Bottom-right corner"},{"id":"b","text":"Center of the dashboard"},{"id":"c","text":"Top-left area"},{"id":"d","text":"Bottom-left corner"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Dashboard layout: F or Z reading pattern; most important info top-left.' Both the F-pattern and Z-pattern describe how users naturally scan content starting from the top-left. Placing the most critical KPIs or charts in the top-left ensures they are seen first. Bottom-right, center, and bottom-left placements reduce the likelihood that key insights will be noticed immediately.$patch$, $patch$Understanding Tableau Concepts$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_best_practices.htm","label":"Dashboard Layout and Design Best Practices — Tableau"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
