INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop, what is the primary advantage of using a Live connection over an Extract?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Faster query performance because data is stored in memory"},{"id":"b","text":"Real-time queries against the source data"},{"id":"c","text":"Automatic removal of merged cells from Excel files"},{"id":"d","text":"Ability to combine tables from different databases"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material states that a Live connection provides 'real-time query against source,' meaning dashboards always reflect the latest data. Extracts are faster because they are in-memory snapshots, not Live connections. Merged-cell removal is handled by the Data Interpreter feature. Cross-database combining is a feature called cross-database joins.$patch$, $patch$Connecting to and Preparing Data$patch$,
         1, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/live_extracts.htm","label":"Tableau Help – Live Connections and Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
